def greedy_color_count(spec: dict) -> int:
    """Greedy-color nodes in alphabetical order (smallest free color); return number of distinct colors used."""
    edges = spec["edges"]
    nbrs = {}
    for e in edges:
        u, v = e[0], e[1]
        nbrs.setdefault(u, set()).add(v)
        nbrs.setdefault(v, set()).add(u)
    color = {}
    for n in sorted(nbrs):
        taken = set()
        for m in nbrs[n]:
            if m in color:
                taken.add(color[m])
        pick = 0
        while pick in taken:
            pick += 1
        color[n] = pick
    return len(set(color.values())) if color else 0

