def component_size_histogram(spec: dict) -> list:
    """Return the sizes of all connected components, sorted descending."""
    names = spec["nodes"]
    edges = spec["edges"]
    nbrs = {n: [] for n in names}
    for e in edges:
        nbrs[e[0]].append(e[1])
        nbrs[e[1]].append(e[0])
    seen = set()
    sizes = []
    for n in sorted(names):
        if n in seen:
            continue
        stack = [n]
        seen.add(n)
        cnt = 0
        while stack:
            cur = stack.pop()
            cnt += 1
            for m in nbrs[cur]:
                if m not in seen:
                    seen.add(m)
                    stack.append(m)
        sizes.append(cnt)
    sizes.sort(reverse=True)
    return sizes

