def shortest_path_count(spec: dict) -> int:
    """Count the distinct shortest (fewest-hop) directed paths from src to dst (0 if unreachable)."""
    edges = spec["edges"]
    src, dst = spec["src"], spec["dst"]
    adj = {}
    for e in edges:
        adj.setdefault(e[0], []).append(e[1])
        adj.setdefault(e[1], [])
    dist = {src: 0}
    ways = {src: 1}
    queue = [src]
    while queue:
        cur = queue.pop(0)
        for m in adj.get(cur, []):
            if m not in dist:
                dist[m] = dist[cur] + 1
                ways[m] = ways[cur]
                queue.append(m)
            elif dist[m] == dist[cur] + 1:
                ways[m] += ways[cur]
    return ways.get(dst, 0)

