def tree_centroid(spec: dict) -> str:
    """Name of the tree centroid: node whose removal minimizes the largest remaining component (ties -> alphabetically first)."""
    edges = spec["edges"]
    nbrs = {}
    for e in edges:
        nbrs.setdefault(e[0], []).append(e[1])
        nbrs.setdefault(e[1], []).append(e[0])
    def comp_size(start, banned):
        seen = {start, banned}
        stack = [start]
        cnt = 1
        while stack:
            cur = stack.pop()
            for m in nbrs[cur]:
                if m not in seen:
                    seen.add(m)
                    cnt += 1
                    stack.append(m)
        return cnt
    best_name = ""
    best_score = -1
    for x in sorted(nbrs):
        score = 0
        for y in nbrs[x]:
            s = comp_size(y, x)
            if s > score:
                score = s
        if best_score == -1 or score < best_score:
            best_score = score
            best_name = x
    return best_name

