def bridge_count(spec: dict) -> int:
    """Count bridges: undirected edges whose removal disconnects their two endpoints."""
    edges = spec["edges"]
    nbrs = {}
    for e in edges:
        nbrs.setdefault(e[0], []).append(e[1])
        nbrs.setdefault(e[1], []).append(e[0])
    def connected_without(u, v):
        seen = {u}
        stack = [u]
        while stack:
            cur = stack.pop()
            for m in nbrs[cur]:
                if (cur == u and m == v) or (cur == v and m == u):
                    continue
                if m not in seen:
                    seen.add(m)
                    stack.append(m)
        return v in seen
    acc = 0
    for e in edges:
        if not connected_without(e[0], e[1]):
            acc += 1
    return acc

