def b_connected_without(reg: dict, u: str, v: str) -> bool {
    seen = set();
    seen.add(u);
    frontier = [reg[u]];
    while len(frontier) > 0 {
        cur = frontier.pop();
        for nb in [cur ->:BL:->] {
            blocked = (cur.name == u and nb.name == v) or (cur.name == v and nb.name == u);
            if not blocked and nb.name not in seen {
                seen.add(nb.name);
                frontier.append(nb);
            }
        }
    }
    return v in seen;
}

