def lca_name(spec: dict) -> str:
    """Name of the lowest common ancestor of nodes p and q in a rooted tree (a node counts as its own ancestor)."""
    children = spec["children"]
    p, q = spec["p"], spec["q"]
    parent = {}
    for f, kids in children.items():
        for k in kids:
            parent[k] = f
    chain_p = [p]
    while chain_p[-1] in parent:
        chain_p.append(parent[chain_p[-1]])
    anc = set(chain_p)
    cur = q
    while cur not in anc:
        cur = parent[cur]
    return cur

