def degree_profile_match(spec: dict) -> bool:
    """True if the two undirected graphs have identical sorted neighbor-degree profiles (structural-equivalence lite)."""
    def profile(edges):
        nbrs = {}
        for e in edges:
            nbrs.setdefault(e[0], []).append(e[1])
            nbrs.setdefault(e[1], []).append(e[0])
        prof = []
        for n, ms in nbrs.items():
            prof.append([len(ms), sorted(len(nbrs[m]) for m in ms)])
        prof.sort()
        return prof
    return profile(spec["g1"]) == profile(spec["g2"])

