def eulerian_path_feasible(spec: dict) -> bool:
    """True if the undirected graph admits an Eulerian path: connected and 0 or 2 odd-degree nodes."""
    edges = spec["edges"]
    nbrs = {}
    for e in edges:
        nbrs.setdefault(e[0], []).append(e[1])
        nbrs.setdefault(e[1], []).append(e[0])
    names = sorted(nbrs)
    seen = {names[0]}
    stack = [names[0]]
    while stack:
        cur = stack.pop()
        for m in nbrs[cur]:
            if m not in seen:
                seen.add(m)
                stack.append(m)
    if len(seen) != len(names):
        return False
    odd = 0
    for n in names:
        if len(nbrs[n]) % 2 == 1:
            odd += 1
    return odd == 0 or odd == 2

